<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __be32             local, remote;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       /* 地址：local 是本地地址，remote 是隧道远端地址 */</span></span>
